[asy]

unitsize(2 cm);

pair A, B, C, M;

A = dir(110);

B = (-1,0);

C = (1,0);

M = (0,0);

draw(A--B--C--cycle);

draw(A--M);

draw(Circle(M,1));

label("$A$", A, dir(90));

label("$B$", B, SW);

label("$C$", C, SE);

dot("$M$", M, S);

[/asy]

